        const angle = angleSlice * i - Math.PI / 2;
        const r = (v / 10) * maxR;
        return [Math.cos(angle) * r, Math.sin(angle) * r];
      });
      points.push(points[0]);

      let path = `M${points[0][0]},${points[0][1]}`;
      for (let i = 0; i < points.length - 1; i++) {
        const curr = points[i];
        const next = points[(i + 1) % points.length];
        const cpx = (curr[0] + next[0]) / 2;
        const cpy = (curr[1] + next[1]) / 2;
        path += `Q${curr[0]},${curr[1]} ${cpx},${cpy}`;
      }
      path += "Z";
      return path;
    };

    const animatePath = (selection, fromData, toData) => {
      const fromValues = fromData || toData.map(() => 0);
      selection
        .attr("d", rosePath(fromValues))
        .transition()
        .duration(800)
        .ease(d3.easeCubicOut)
        .attrTween("d", () => {
          const interp = fromValues.map((from, i) => d3.interpolate(from, toData[i]));
          return (t) => rosePath(interp.map((fn) => fn(t)));
        });
    };

    if (compareData) {
      const compareGlowFilter = g.append("defs").append("filter").attr("id", "compareGlow");
      compareGlowFilter.append("feGaussianBlur").attr("stdDeviation", "6").attr("result", "blur");
      compareGlowFilter.append("feComposite").attr("in", "SourceGraphic").attr("in2", "blur");

      const compareShape = g.append("path")
        .attr("fill", compareColor)
        .attr("fill-opacity", isDark ? 0.08 : 0.1)
        .attr("stroke", compareColor)
        .attr("stroke-width", 1.5)
        .attr("stroke-opacity", isDark ? 0.5 : 0.6)
        .attr("filter", "url(#compareGlow)")
        .style("stroke-dasharray", "6,4");

      animatePath(compareShape, prevCompareRef.current, compareData);

      compareData.forEach((v, i) => {
        const angle = angleSlice * i - Math.PI / 2;
        const r = (v / 10) * maxR;
        g.append("circle")
          .attr("cx", Math.cos(angle) * r)
          .attr("cy", Math.sin(angle) * r)
          .attr("r", 3)
          .attr("fill", compareColor)
          .attr("fill-opacity", 0)
          .transition()
          .delay(400 + i * 40)
          .duration(400)
          .attr("fill-opacity", 0.7);
      });
    }

    const glowFilter = g.append("defs").append("filter").attr("id", "mainGlow");
    glowFilter.append("feGaussianBlur").attr("stdDeviation", "8").attr("result", "blur");
    glowFilter.append("feComposite").attr("in", "SourceGraphic").attr("in2", "blur");

    const glowShape = g.append("path")
      .attr("fill", color)
      .attr("fill-opacity", isDark ? 0.12 : 0.08)
      .attr("stroke", "none")
      .attr("filter", "url(#mainGlow)");
    animatePath(glowShape, prevDataRef.current, data);

    const mainShape = g.append("path")
      .attr("fill", color)
      .attr("fill-opacity", isDark ? 0.15 : 0.12)
      .attr("stroke", color)
      .attr("stroke-width", 2)
      .attr("stroke-opacity", isDark ? 0.9 : 0.8);
    animatePath(mainShape, prevDataRef.current, data);

    data.forEach((v, i) => {
      const angle = angleSlice * i - Math.PI / 2;
      const r = (v / 10) * maxR;

      g.append("circle")
        .attr("cx", Math.cos(angle) * r)
        .attr("cy", Math.sin(angle) * r)
        .attr("r", 6)
        .attr("fill", color)
        .attr("fill-opacity", 0)
        .transition().delay(400 + i * 50).duration(400)
        .attr("fill-opacity", 0.25);

      g.append("circle")
        .attr("cx", Math.cos(angle) * r)
        .attr("cy", Math.sin(angle) * r)
        .attr("r", 3.5)
        .attr("fill", color)
        .attr("fill-opacity", 0)
        .transition().delay(400 + i * 50).duration(400)
        .attr("fill-opacity", 1);

      g.append("circle")
        .attr("cx", Math.cos(angle) * r)
        .attr("cy", Math.sin(angle) * r)
        .attr("r", 1.5)
        .attr("fill", dotCenter)
        .attr("fill-opacity", 0)
        .transition().delay(500 + i * 50).duration(300)
        .attr("fill-opacity", 0.8);
    });

    data.forEach((v, i) => {
      const angle = angleSlice * i - Math.PI / 2;
      const r = (v / 10) * maxR + 10;
      if (v > 0) {
        g.append("text")
          .attr("x", Math.cos(angle) * r)
          .attr("y", Math.sin(angle) * r)
          .attr("text-anchor", "middle")
          .attr("dominant-baseline", "middle")
          .attr("fill", color)
          .attr("font-size", "10px")
          .attr("font-family", "'DM Sans', sans-serif")
          .attr("font-weight", 700)
          .attr("opacity", 0)
          .text(v)
          .transition().delay(600 + i * 50).duration(400)
          .attr("opacity", 0.8);
      }
    });

    prevDataRef.current = data;
    prevCompareRef.current = compareData;
  }, [data, color, glow, compareData, compareColor, compareGlow, size, isDark]);

  return <svg ref={svgRef} width={size} height={size} />;
}

function App() {
  const [archetype, setArchetype] = useState("storyteller");
  const [level, setLevel] = useState("senior");
  const [compareArchetype, setCompareArchetype] = useState(null);
  const [chartSize, setChartSize] = useState(520);
  const [isDark, setIsDark] = useState(true);
  const containerRef = useRef(null);

  useEffect(() => {
    document.documentElement.setAttribute("data-theme", isDark ? "dark" : "light");
  }, [isDark]);

  useEffect(() => {
    const handleResize = () => {
      if (containerRef.current) {
        const w = containerRef.current.offsetWidth;
        setChartSize(Math.min(Math.max(w * 0.7, 340), 560));
      }
    };
    handleResize();
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  const currentData = DATA[archetype][level];
  const compareData = compareArchetype ? DATA[compareArchetype][level] : null;
  const arc = ARCHETYPES[archetype];
  const cmpArc = compareArchetype ? ARCHETYPES[compareArchetype] : null;

  /* Theme-aware colors */
  const accentColor = isDark ? arc.color : arc.colorLight;
  const accentGlow = isDark ? arc.glow : arc.glowLight;
  const cmpColor = cmpArc ? (isDark ? cmpArc.color : cmpArc.colorLight) : null;
  const cmpGlow = cmpArc ? (isDark ? cmpArc.glow : cmpArc.glowLight) : null;

  const topCompetencies = useMemo(() => {
    return currentData
      .map((v, i) => ({ name: COMPETENCIES[i], value: v }))
      .sort((a, b) => b.value - a.value)
      .slice(0, 3);
  }, [currentData]);

  /* Theme palette */
  const bg = t(isDark, "#0B0B0F", "#F2F3F7");
  const text1 = t(isDark, "#fff", "#1a1a2e");
  const textDim = t(isDark, "rgba(255,255,255,0.55)", "rgba(0,0,0,0.55)");
  const textMuted = t(isDark, "rgba(255,255,255,0.35)", "rgba(0,0,0,0.35)");
  const textFaint = t(isDark, "rgba(255,255,255,0.25)", "rgba(0,0,0,0.2)");
  const textGhost = t(isDark, "rgba(255,255,255,0.3)", "rgba(0,0,0,0.3)");
  const textSubtle = t(isDark, "rgba(255,255,255,0.4)", "rgba(0,0,0,0.4)");
  const textMid = t(isDark, "rgba(255,255,255,0.5)", "rgba(0,0,0,0.45)");
  const textStrong = t(isDark, "rgba(255,255,255,0.7)", "rgba(0,0,0,0.7)");
  const textWhite = t(isDark, "#fff", "#1a1a2e");
  const borderLight = t(isDark, "rgba(255,255,255,0.06)", "rgba(0,0,0,0.07)");
  const borderMed = t(isDark, "rgba(255,255,255,0.08)", "rgba(0,0,0,0.1)");
  const borderActive = t(isDark, "rgba(255,255,255,0.2)", "rgba(0,0,0,0.2)");
  const surfaceSoft = t(isDark, "rgba(255,255,255,0.03)", "rgba(0,0,0,0.03)");
  const surfaceCard = t(isDark, "rgba(255,255,255,0.02)", "rgba(0,0,0,0.03)");
  const barTrack = t(isDark, "rgba(255,255,255,0.06)", "rgba(0,0,0,0.06)");
  const textItalic = t(isDark, "rgba(255,255,255,0.2)", "rgba(0,0,0,0.25)");
  const grainOpacity = isDark ? 0.03 : 0.015;

  return (
    <div style={{
      minHeight: "100vh",
      background: bg,
      fontFamily: "'DM Sans', sans-serif",
      color: text1,
      position: "relative",
      overflow: "hidden",
      transition: "background 0.5s ease, color 0.5s ease",
    }}>
      {/* Theme toggle */}
      <div className="theme-toggle" onClick={() => setIsDark(!isDark)} title={isDark ? "Switch to light mode" : "Switch to dark mode"}>
        <div className="knob">{isDark ? "\u{1F319}" : "\u{2600}\uFE0F"}</div>
      </div>

      {/* Ambient glows */}
      <div style={{
        position: "fixed", top: "-30%", left: "-10%",
        width: "60%", height: "60%", borderRadius: "50%",
        background: `radial-gradient(circle, ${accentGlow} 0%, transparent 70%)`,
        filter: `blur(${isDark ? 80 : 100}px)`, pointerEvents: "none",
        transition: "background 0.8s ease, filter 0.5s ease",
        opacity: isDark ? 1 : 0.6,
      }} />
      <div style={{
        position: "fixed", bottom: "-20%", right: "-10%",
        width: "50%", height: "50%", borderRadius: "50%",
        background: `radial-gradient(circle, ${cmpGlow || (isDark ? "rgba(255,255,255,0.02)" : "rgba(0,0,0,0.01)")} 0%, transparent 70%)`,
        filter: `blur(${isDark ? 80 : 100}px)`, pointerEvents: "none",
        transition: "background 0.8s ease, filter 0.5s ease",
        opacity: isDark ? 1 : 0.5,
      }} />

      {/* Grain */}
      <div style={{
        position: "fixed", inset: 0, pointerEvents: "none", opacity: grainOpacity, zIndex: 100,
        backgroundImage: `url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)'/%3E%3C/svg%3E")`,
        transition: "opacity 0.5s ease",
      }} />

      <div style={{ position: "relative", zIndex: 10, maxWidth: 1100, margin: "0 auto", padding: "40px 24px 60px" }}>

        {/* Header */}
        <div style={{ marginBottom: 40 }}>
          <h1 style={{
            fontFamily: "'Syne', sans-serif", fontWeight: 800,
            fontSize: "clamp(1.8rem, 4vw, 2.8rem)",
            letterSpacing: "-0.02em", lineHeight: 1,
            background: `linear-gradient(135deg, ${accentColor}, ${textWhite})`,
            WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent",
            transition: "all 0.6s ease", marginBottom: 6,
          }}>
            Competency Radar
          </h1>
          <p style={{ color: textMuted, fontSize: 13, letterSpacing: "0.15em", fontWeight: 200, textTransform: "uppercase", transition: "color 0.5s" }}>
            Designer Archetype × Career Level
          </p>
        </div>

        <div style={{ display: "flex", gap: 40, flexWrap: "wrap" }}>

          {/* Left: Controls */}
          <div style={{ flex: "0 0 280px", minWidth: 240 }}>
            {/* Archetype */}
            <div style={{ marginBottom: 28 }}>
              <label style={{ display: "block", fontSize: 10, letterSpacing: "0.2em", textTransform: "uppercase", color: textGhost, marginBottom: 10, fontWeight: 500, transition: "color 0.5s" }}>
                Archetype
              </label>
              <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
                {Object.entries(ARCHETYPES).map(([key, a]) => {
                  const ac = isDark ? a.color : a.colorLight;
                  return (
                    <button
                      key={key}
                      onClick={() => { setArchetype(key); if (compareArchetype === key) setCompareArchetype(null); }}
                      style={{
                        background: archetype === key ? `${ac}${isDark ? "12" : "14"}` : "transparent",
                        border: `1px solid ${archetype === key ? ac + "60" : borderLight}`,
                        borderRadius: 8, padding: "10px 14px",
                        cursor: "pointer", textAlign: "left",
                        transition: "all 0.3s ease",
                      }}
                    >
                      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                        <div style={{
                          width: 8, height: 8, borderRadius: "50%",
                          background: ac, boxShadow: archetype === key ? `0 0 12px ${ac}` : "none",
                          transition: "box-shadow 0.3s ease",
                        }} />
                        <div>
                          <div style={{ fontSize: 13, fontWeight: archetype === key ? 700 : 400, color: archetype === key ? textWhite : textDim, transition: "all 0.3s" }}>
                            {a.name}
                          </div>
                          <div style={{ fontSize: 10, color: textFaint, marginTop: 1, transition: "color 0.5s" }}>{a.sub}</div>
                        </div>
                      </div>
                    </button>
                  );
                })}
              </div>
            </div>

            {/* Level */}
            <div style={{ marginBottom: 28 }}>
              <label style={{ display: "block", fontSize: 10, letterSpacing: "0.2em", textTransform: "uppercase", color: textGhost, marginBottom: 10, fontWeight: 500, transition: "color 0.5s" }}>
                Career Level
              </label>
              <div style={{ display: "flex", flexWrap: "wrap", gap: 4 }}>
                {Object.entries(LEVELS).map(([key, name]) => (
                  <button
                    key={key}
                    onClick={() => setLevel(key)}
                    style={{
                      background: level === key ? `${accentColor}${isDark ? "18" : "14"}` : surfaceSoft,
                      border: `1px solid ${level === key ? accentColor + "50" : borderLight}`,
                      color: level === key ? textWhite : textSubtle,
                      borderRadius: 6, padding: "7px 12px",
                      fontSize: 11, fontWeight: level === key ? 600 : 400,
                      cursor: "pointer", transition: "all 0.3s ease",
                      fontFamily: "'DM Sans', sans-serif",
                    }}
                  >
                    {name}
                  </button>
                ))}
              </div>
            </div>

            {/* Compare */}
            <div style={{ marginBottom: 28 }}>
              <label style={{ display: "block", fontSize: 10, letterSpacing: "0.2em", textTransform: "uppercase", color: textGhost, marginBottom: 10, fontWeight: 500, transition: "color 0.5s" }}>
                Compare With
              </label>
              <div style={{ display: "flex", flexWrap: "wrap", gap: 4 }}>
                <button
                  onClick={() => setCompareArchetype(null)}
                  style={{
                    background: !compareArchetype ? (isDark ? "rgba(255,255,255,0.08)" : "rgba(0,0,0,0.06)") : surfaceSoft,
                    border: `1px solid ${!compareArchetype ? borderActive : borderLight}`,
                    color: !compareArchetype ? textWhite : textMuted,
                    borderRadius: 6, padding: "6px 12px", fontSize: 11,
                    cursor: "pointer", transition: "all 0.3s ease",
                    fontFamily: "'DM Sans', sans-serif",
                  }}
                >
                  None
                </button>
                {Object.entries(ARCHETYPES).filter(([k]) => k !== archetype).map(([key, a]) => {
                  const ac = isDark ? a.color : a.colorLight;
                  return (
                    <button
                      key={key}
                      onClick={() => setCompareArchetype(key)}
                      style={{
                        background: compareArchetype === key ? `${ac}${isDark ? "18" : "14"}` : surfaceSoft,
                        border: `1px solid ${compareArchetype === key ? ac + "50" : borderLight}`,
                        borderRadius: 6, padding: "5px 10px",
                        cursor: "pointer", transition: "all 0.3s ease",
                        display: "flex", alignItems: "center", gap: 6,
                        fontFamily: "'DM Sans', sans-serif",
                      }}
                    >
                      <div style={{ width: 6, height: 6, borderRadius: "50%", background: ac }} />
                      <span style={{ fontSize: 10, color: compareArchetype === key ? textWhite : textMuted, transition: "color 0.5s" }}>
                        {a.name.split(" ")[0]}
                      </span>
                    </button>
                  );
                })}
              </div>
            </div>

            {/* Peak Strengths */}
            <div style={{
              background: surfaceCard,
              border: `1px solid ${borderLight}`,
              borderRadius: 10, padding: 16,
              transition: "all 0.5s ease",
            }}>
              <label style={{ display: "block", fontSize: 10, letterSpacing: "0.2em", textTransform: "uppercase", color: textGhost, marginBottom: 12, fontWeight: 500, transition: "color 0.5s" }}>
                Peak Strengths
              </label>
              {topCompetencies.map((c, i) => (
                <div key={c.name} style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: i < 2 ? 10 : 0 }}>
                  <span style={{ fontFamily: "'Syne', sans-serif", fontSize: 22, fontWeight: 800, color: accentColor, minWidth: 30, transition: "color 0.6s" }}>
                    {c.value}
                  </span>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontSize: 12, fontWeight: 500, color: textStrong, transition: "color 0.5s" }}>{c.name}</div>
                    <div style={{
                      marginTop: 4, height: 3, borderRadius: 2,
                      background: barTrack,
                      overflow: "hidden",
                      transition: "background 0.5s ease",
                    }}>
                      <div style={{
                        height: "100%", borderRadius: 2,
                        width: `${c.value * 10}%`,
                        background: `linear-gradient(90deg, ${accentColor}, ${accentColor}88)`,
                        transition: "all 0.8s cubic-bezier(0.16,1,0.3,1)",
                      }} />
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Right: Chart */}
          <div ref={containerRef} style={{ flex: 1, minWidth: 300, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center" }}>
            <div style={{ display: "flex", gap: 24, marginBottom: 16, flexWrap: "wrap", justifyContent: "center" }}>
              <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                <div style={{ width: 20, height: 3, borderRadius: 2, background: accentColor, transition: "background 0.6s" }} />
                <span style={{ fontSize: 11, color: textMid, transition: "color 0.5s" }}>{arc.name}</span>
              </div>
              {cmpArc && (
                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                  <div style={{ width: 20, height: 3, borderRadius: 2, background: cmpColor, opacity: 0.6, borderTop: `1px dashed ${cmpColor}` }} />
                  <span style={{ fontSize: 11, color: textMid, transition: "color 0.5s" }}>{cmpArc.name}</span>
                </div>
              )}
            </div>

            <RoseChart
              data={currentData}
              color={accentColor}
              glow={accentGlow}
              compareData={compareData}
              compareColor={cmpColor}
              compareGlow={cmpGlow}
              size={chartSize}
              isDark={isDark}
            />

            <p style={{ fontSize: 11, color: textItalic, marginTop: 12, textAlign: "center", fontStyle: "italic", maxWidth: 380, transition: "color 0.5s" }}>
              Scores represent relative competency emphasis — not absolute skill. Every archetype needs all ten; the shape shows where each one leads.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

ReactDOM.createRoot(document.getElementById("root")).render(<App />);
</script>
</body>
</html>
